from __future__ import annotations
import csv,json,os
from datetime import date,datetime,timedelta
from typing import Any
OUT='docs/index.html'

def load_json(p:str,d:Any):
    try:
        if os.path.exists(p): return json.load(open(p,encoding='utf-8'))
    except Exception: pass
    return d

def read_csv(p:str):
    try:
        if os.path.exists(p): return list(csv.DictReader(open(p,encoding='utf-8')))
    except Exception: pass
    return []

def target(): return os.environ.get('TARGET') or os.environ.get('WNBA_TARGET_DATE') or str(date.today())
def yday(t):
    try: return str(datetime.strptime(t,'%Y-%m-%d').date()-timedelta(days=1))
    except Exception: return str(date.today()-timedelta(days=1))
def first(paths):
    for p in paths:
        r=read_csv(p)
        if r: return r
    return []

def payload():
    t=target(); y=yday(t); master=load_json('data/dashboard/wnba_master.json',{}); sb=load_json('data/dashboard/wnba_sportsbook_consensus.json',{})
    games=master.get('games',[]) if isinstance(master,dict) else []
    today=[g for g in games if g.get('bucket')=='today'] or first([f'data/raw/scores_{t}.csv','data/raw/scores_today.csv'])
    yesterday=[g for g in games if g.get('bucket')=='yesterday'] or first([f'data/raw/scores_{y}.csv'])
    return {'target_date':master.get('target_date') or t,'generated_at_utc':master.get('generated_at_utc') or datetime.utcnow().isoformat()+'Z','master':master,'today_scores':today,'yesterday_scores':yesterday,'sportsbook_consensus':sb,'odds_health':load_json('data/dashboard/wnba_odds_health.json',{}),'stats_quality':load_json('data/dashboard/wnba_stats_quality.json',{}),'source_health':load_json('data/dashboard/wnba_source_health.json',{}),'autonomous_agent':load_json('data/dashboard/wnba_autonomous_agent.json',{}),'decision':load_json('data/dashboard/wnba_decision_engine_final.json',{}),'consensus':load_json('data/dashboard/wnba_consensus_engine.json',{}),'matchups':load_json('data/dashboard/wnba_matchup_intelligence.json',{}),'portfolio':load_json('data/dashboard/wnba_portfolio_dashboard.json',{}),'risk':load_json('data/dashboard/wnba_risk_allocation.json',{}),'grading':load_json('data/dashboard/wnba_results_grading.json',{}),'ai_coach':load_json('data/dashboard/wnba_ai_coach.json',{}),'monte_carlo':load_json('data/dashboard/wnba_monte_carlo_engine.json',{}),'projection_ai':load_json('data/dashboard/wnba_projection_ai.json',{}),'market':load_json('data/dashboard/wnba_market_engine.json',{}),'learning':load_json('data/dashboard/wnba_self_learning.json',{})}

HTML='''<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>WNBA Model</title><style>:root{--p:#0d1424;--m:#8b96ad;--t:#edf2ff;--l:#22304c;--g:#00e5a0;--r:#ff6b7a;--b:#7aa2ff;--y:#ffd166}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at top right,#112441,#070912 45%,#05060b);color:var(--t);font-family:Courier New,monospace}.app{max-width:1220px;margin:auto;padding:16px 10px 60px}.top{display:flex;justify-content:space-between;gap:12px}.ey{font-size:12px;letter-spacing:.3em;color:#86a8ff}.title{font-size:30px;font-weight:900;letter-spacing:.08em}.sub,.small{color:var(--m);font-size:12px}.pill{border:1px solid var(--l);background:#10192b;border-radius:999px;padding:8px 12px;height:max-content}.tabs{display:flex;gap:8px;overflow:auto;padding:10px;background:var(--p);border:1px solid var(--l);border-radius:18px;position:sticky;top:0;z-index:5;margin-top:14px}.tab{white-space:nowrap;background:transparent;color:#94a3b8;border:0;padding:10px 12px;border-radius:12px;font-weight:900;font-family:inherit}.tab.a{background:#1c2b49;color:white}.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.grid2{display:grid;grid-template-columns:1fr 1fr;gap:12px}.grid3{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.card,.panel{background:linear-gradient(180deg,#101827,#0a0f1d);border:1px solid var(--l);border-radius:18px;padding:15px;margin-top:12px}.label{font-size:11px;color:#7f8ba2;text-transform:uppercase;letter-spacing:.18em}.val{font-size:27px;font-weight:900;color:var(--g);margin-top:6px}.red{color:var(--r)}.blue{color:var(--b)}.gold{color:var(--y)}.pt{font-size:18px;font-weight:900;margin-bottom:10px}.row{border:1px solid #1d2a43;background:#0b1220;border-radius:14px;padding:12px;margin:8px 0}.rt{display:flex;justify-content:space-between;gap:10px}.score{font-size:22px;font-weight:900}.tag{font-size:11px;border:1px solid #2c3c5f;border-radius:999px;padding:4px 8px;color:#b9c8e8}.filterbar{display:grid;grid-template-columns:2fr 1fr 1fr 1fr 1fr;gap:8px;margin-top:12px}.filterbar input,.filterbar select{background:#0a1020;border:1px solid var(--l);border-radius:12px;color:white;padding:12px;font-family:inherit;min-width:0}.gameHead{display:flex;justify-content:space-between;gap:10px;align-items:center;margin-bottom:8px}.count{color:var(--g);font-weight:900}.tableWrap{overflow:auto}table{width:100%;border-collapse:collapse;min-width:760px}th,td{border-bottom:1px solid #1f2b45;padding:10px 8px;text-align:left;font-size:12px}th{color:#89a2cc;text-transform:uppercase}.empty{text-align:center;color:#7f8ba2;padding:28px}@media(max-width:860px){.grid,.grid2,.grid3,.filterbar{grid-template-columns:1fr}.title{font-size:24px}.tableWrap{margin-left:-4px;margin-right:-4px}}</style><script>const DATA=__DATA__;</script></head><body><div class="app"><div class="top"><div><div class="ey">WNBA MODEL</div><div class="title">Daily Report</div><div class="sub" id="sub"></div></div><div class="pill" id="pill"></div></div><div class="tabs" id="tabs"></div><div id="content"></div></div><script>
const tabs=[['games','Games'],['matchups','Matchups'],['props','Player Props'],['books','Sportsbooks'],['best','Best Bets'],['ai','AI Center'],['live','Live'],['results','Results'],['portfolio','Portfolio'],['health','Data Health']];
const $=i=>document.getElementById(i), A=x=>Array.isArray(x)?x:[], S=(v,d='-')=>v===undefined||v===null||v===''?d:v, P=(o,ks,d)=>{for(const k of ks){if(!o||o[k]===undefined)return d;o=o[k]}return o};
function fmtDate(v){let d=new Date(v);return isNaN(d)?new Date().toLocaleString():d.toLocaleString()}
function game(g){return S(g.game)||[S(g.away_team||P(g,['away','name'],''),''),S(g.home_team||P(g,['home','name'],''),'')].filter(Boolean).join(' @ ')||'WNBA Game'}
function score(g){let a=S(g.away_score||P(g,['away','score'],''),'');let h=S(g.home_score||P(g,['home','score'],''),'');return a!==''||h!==''?a+'-'+h:S(g.score,'')}
function cards(){let ms=P(DATA,['master','summary'],{}),sb=P(DATA,['sportsbook_consensus','summary'],{}),lp=ms.players||P(DATA,['stats_quality','summary','live_players'],0);return `<div class="grid"><div class="card"><div class="label">Odds</div><div class="val ${ms.sportsbook_markets?'':'red'}">${ms.sportsbook_markets?'Loaded':'Missing'}</div><div class="small">${S(ms.sportsbook_markets||sb.markets,0)} markets</div></div><div class="card"><div class="label">Props</div><div class="val">Loaded</div><div class="small">${S(ms.props,0)} rows</div></div><div class="card"><div class="label">Stats</div><div class="val ${lp?'':'red'}">${lp?'Loaded':'Missing'}</div><div class="small">${lp} players</div></div><div class="card"><div class="label">Best Bets</div><div class="val">${S(ms.best_bets,0)}</div><div class="small">From master projection edge</div></div></div>`}
function games(){let g=A(DATA.today_scores),y=A(DATA.yesterday_scores);return cards()+`<div class="grid2"><div class="panel"><div class="pt">Today's Games</div>${g.map(x=>`<div class="row"><div class="rt"><div><b>${game(x)}</b><div class="small">${S(x.start_time||x.tip||x.commence_time||x.date,'Time TBD')} · ${S(x.status||x.game_status||x.source,'Pregame')}</div></div><div class="score">${score(x)}</div></div><div style="margin-top:10px"><span class="tag">Spread ${S(x.spread||x.spread_home)}</span> <span class="tag">Total ${S(x.total)}</span></div></div>`).join('')||'<div class="empty">No games loaded.</div>'}</div><div class="panel"><div class="pt">Yesterday Results</div>${y.map(x=>`<div class="row"><div class="rt"><div><b>${game(x)}</b><div class="small">Final</div></div><div class="score">${score(x)}</div></div></div>`).join('')||'<div class="empty">No previous results loaded.</div>'}</div></div>`}
function matchups(){let m=A(P(DATA,['matchups','matchups'],[]));if(!m.length)m=A(DATA.today_scores);return `<div class="grid2">${m.slice(0,40).map(x=>`<div class="card"><div class="label">Matchup</div><div class="pt">${game(x)}</div><span class="tag">Pace ${S(x.pace||x.pace_score)}</span> <span class="tag">Edge ${S(x.edge||x.matchup_score)}</span> <span class="tag">Lean ${S(x.lean||x.signal)}</span><p class="small">${S(x.note||x.summary||x.reason,'Team analysis will grow as data collects.')}</p></div>`).join('')||'<div class="empty">No matchup cards yet.</div>'}</div>`}
function propData(){return A(P(DATA,['master','props'],[])).length?A(P(DATA,['master','props'],[])):A(P(DATA,['sportsbook_consensus','markets'],[]))}
function uniq(vals){return [...new Set(vals.filter(x=>x!==undefined&&x!==null&&String(x).trim()!==''))].sort()}
function normGameName(g){return S(g,'Unknown Game')}
function props(){let p=propData();let games=uniq(p.map(r=>normGameName(r.game)));let stats=uniq(p.map(r=>S(r.stat,'')));let books=uniq(p.map(r=>S(r.book||r.best_book||r.best_over_book,'')));return `<div class="filterbar"><input id="q" placeholder="Search player, team, stat" oninput="filterProps()"><select id="gameFilter" onchange="filterProps()"><option value="">All games</option>${games.map(g=>`<option>${g}</option>`).join('')}</select><select id="statFilter" onchange="filterProps()"><option value="">All stats</option>${stats.map(s=>`<option>${s}</option>`).join('')}</select><select id="sideFilter" onchange="filterProps()"><option value="">All sides</option><option>OVER</option><option>UNDER</option><option>PASS</option></select><select id="bookFilter" onchange="filterProps()"><option value="">All books</option>${books.map(b=>`<option>${b}</option>`).join('')}</select></div><div class="panel"><div class="rt"><div><div class="pt">Player Props by Game</div><div class="small" id="propCount"></div></div><button class="tab" onclick="clearPropFilters()">Clear</button></div><div id="propGroups"></div></div>`}
function propRows(p){return p.map(r=>`<tr><td>${S(r.player)}</td><td>${S(r.stat)}</td><td>${S(r.line||r.consensus_line)}</td><td>${S(r.pred||r.projection||r.ai_projection)}</td><td>${S(r.edge)}</td><td>${S(r.signal||r.side)}</td><td>${S(r.book||r.best_book||r.best_over_book||r.source)}</td></tr>`).join('')||'<tr><td colspan="7" class="empty">No props match filters.</td></tr>'}
function renderPropGroups(rows){let groups={};rows.forEach(r=>{let g=normGameName(r.game);(groups[g]=groups[g]||[]).push(r)});let html=Object.keys(groups).sort().map(g=>`<div class="row"><div class="gameHead"><div><b>${g}</b><div class="small">${groups[g].length} props</div></div><span class="count">${groups[g].filter(x=>['OVER','UNDER'].includes(S(x.signal||x.side,''))).length} picks</span></div><div class="tableWrap"><table><thead><tr><th>Player</th><th>Stat</th><th>Line</th><th>Proj</th><th>Edge</th><th>Side</th><th>Book</th></tr></thead><tbody>${propRows(groups[g])}</tbody></table></div></div>`).join('');$('propGroups').innerHTML=html||'<div class="empty">No props match filters.</div>';$('propCount').textContent=`Showing ${rows.length} of ${propData().length} props`}
function filterProps(){let q=S($('q')?.value,'').toLowerCase(),gf=S($('gameFilter')?.value,''),sf=S($('statFilter')?.value,''),side=S($('sideFilter')?.value,''),bf=S($('bookFilter')?.value,'');let rows=propData().filter(r=>(!q||JSON.stringify(r).toLowerCase().includes(q))&&(!gf||normGameName(r.game)===gf)&&(!sf||S(r.stat,'')===sf)&&(!side||S(r.signal||r.side,'')===side)&&(!bf||S(r.book||r.best_book||r.best_over_book,'')===bf));renderPropGroups(rows)}
function clearPropFilters(){['q','gameFilter','statFilter','sideFilter','bookFilter'].forEach(id=>{if($(id))$(id).value=''});filterProps()}
function books(){let m=A(P(DATA,['sportsbook_consensus','markets'],[]));return cards()+`<div class="panel"><div class="pt">Best Available Lines</div><div class="tableWrap"><table><thead><tr><th>Player</th><th>Stat</th><th>Line</th><th>Best Over</th><th>Best Under</th><th>Books</th></tr></thead><tbody>${m.slice(0,140).map(x=>`<tr><td>${S(x.player)}</td><td>${S(x.stat)}</td><td>${S(x.consensus_line)}</td><td>${S(x.best_over_book)} ${S(x.best_over_price)}</td><td>${S(x.best_under_book)} ${S(x.best_under_price)}</td><td>${A(x.books).join(', ')}</td></tr>`).join('')||'<tr><td colspan="6" class="empty">No sportsbook markets.</td></tr>'}</tbody></table></div></div>`}
function bestData(){let b=A(P(DATA,['master','best_bets'],[]));if(!b.length)b=A(P(DATA,['decision','top_decisions'],[]));if(!b.length)b=A(P(DATA,['consensus','top_consensus'],[]));return b}
function best(){let b=bestData();return `<div class="grid2">${b.slice(0,30).map(r=>`<div class="card"><div class="label">${S(r.final_action||r.recommendation||r.action,'Watch')}</div><div class="pt">${S(r.player)} ${S(r.stat)} ${S(r.signal||r.side)}</div><div class="small">${S(r.game)} · ${S(r.book||r.best_book)}</div><span class="tag">Score ${S(r.final_score||r.consensus_score||r.confidence)}</span> <span class="tag">Line ${S(r.line)}</span> <span class="tag">Proj ${S(r.projection||r.pred)}</span></div>`).join('')||'<div class="empty">No best bets yet.</div>'}</div>`}
function ai(){let c=A(P(DATA,['ai_coach','coach_cards'],[]));return `<div class="grid3"><div class="card"><div class="label">Agent</div><div class="val">${S(P(DATA,['autonomous_agent','agent_action'],'-'))}</div></div><div class="card"><div class="label">Monte Carlo</div><div class="val">${S(P(DATA,['monte_carlo','summary','rows'],0))}</div></div><div class="card"><div class="label">Projection AI</div><div class="val">${S(P(DATA,['projection_ai','summary','rows'],0))}</div></div></div><div class="panel"><div class="pt">AI Coach</div>${c.slice(0,10).map(x=>`<div class="row"><b>${S(x.play)}</b><div class="small">${S(x.coach_note)}</div></div>`).join('')||'<div class="empty">No coach notes yet.</div>'}</div>`}
function live(){let l=A(DATA.today_scores).filter(x=>String(S(x.status||x.game_status,'')).toLowerCase().includes('live'));return `<div class="panel"><div class="pt">Live Center</div>${l.map(x=>`<div class="row"><div class="rt"><b>${game(x)}</b><div class="score">${score(x)}</div></div></div>`).join('')||'<div class="empty">No games live right now.</div>'}</div>`}
function results(){let g=DATA.grading||{};return `<div class="grid"><div class="card"><div class="label">Completed</div><div class="val">${S(g.graded_this_run,0)}</div></div><div class="card"><div class="label">Wins</div><div class="val">${S(g.wins,0)}</div></div><div class="card"><div class="label">Losses</div><div class="val red">${S(g.losses,0)}</div></div><div class="card"><div class="label">Win Rate</div><div class="val gold">${S(g.win_rate,'-')}</div></div></div><div class="panel"><div class="pt">Lessons</div><pre>${JSON.stringify(g.lessons||['No completed results found yet.'],null,2)}</pre></div>`}
function portfolio(){let p=DATA.portfolio||{},r=DATA.risk||{},card=A(p.recommended_card||r.allocation);return `<div class="grid"><div class="card"><div class="label">Card Size</div><div class="val">${card.length}</div></div><div class="card"><div class="label">Exposure</div><div class="val">${S(P(r,['summary','total_exposure'],0))}</div></div><div class="card"><div class="label">Exposure %</div><div class="val">${S(P(r,['summary','exposure_pct'],0))}</div></div><div class="card"><div class="label">Teams</div><div class="val">${S(P(r,['summary','teams'],0))}</div></div></div><div class="panel"><div class="pt">Allocation</div>${card.slice(0,20).map(x=>`<div class="row"><b>${S(x.player)} ${S(x.stat)} ${S(x.signal)}</b><div class="small">${S(x.game)} · stake ${S(x.capped_amount||x.capped_stake||x.recommended_stake)}</div></div>`).join('')||'<div class="empty">No allocation built yet.</div>'}</div>`}
function health(){let matrix=A(P(DATA,['master','source_matrix'],[]));return cards()+`<div class="panel"><div class="pt">Data Source Matrix</div>${matrix.length?matrix.map(v=>`<div class="row"><div class="rt"><b>${S(v.source)}</b><span class="tag">${S(v.status)}</span></div><div class="small">${S(v.detail)} · rows ${S(v.rows,0)}</div></div>`).join(''):'<div class="empty">No source health built.</div>'}</div>`}
function render(t='games'){$('tabs').innerHTML=tabs.map(x=>`<button class="tab ${x[0]===t?'a':''}" onclick="render('${x[0]}')">${x[1]}</button>`).join('');$('sub').textContent=`Slate ${S(DATA.target_date,'-')} · Updated ${fmtDate(DATA.generated_at_utc)}`;$('pill').textContent=`${S(P(DATA,['master','summary','sportsbook_markets'],0),0)} odds markets`;$('content').innerHTML={games,matchups,props,books,best,ai,live,results,portfolio,health}[t]();if(t==='props')filterProps();scrollTo(0,0)}render();
</script></body></html>'''

def main():
    os.makedirs('docs',exist_ok=True)
    open(OUT,'w',encoding='utf-8').write(HTML.replace('__DATA__',json.dumps(payload(),separators=(',',':'),ensure_ascii=False)))
    print('Dashboard navigation v2 populated from master with grouped props')
if __name__=='__main__': main()
